const express = require('express');
const axios = require('axios');

const app = express();
app.use(express.json());

const PORT = process.env.PORT || 3000;
const PREMBLY_APP_ID = process.env.PREMBLY_APP_ID;
const PREMBLY_API_KEY = process.env.PREMBLY_API_KEY;

app.post('/api/wallet/create', async (req, res) => {
  const { ninNumber, faceLivelinessRef } = req.body;

  if (!ninNumber) {
    return res.status(400).json({ error: 'ninNumber is required' });
  }

  try {
    const response = await axios.post(
      'https://api.prembly.com/verification/nin',
      { number: ninNumber },
      {
        headers: {
          'app-id': PREMBLY_APP_ID,
          'x-api-key': PREMBLY_API_KEY,
        },
      }
    );

    // Prembly typically returns status: true for successful verification
    if (response.data && response.data.status === true) {
      return res.status(201).json({ wallet_id: 'new_wallet_123' });
    } else {
      return res.status(400).json({ error: 'NIN verification failed', details: response.data });
    }
  } catch (error) {
    // Handle cases where the API returns an error status code
    return res.status(400).json({ 
      error: 'NIN verification failed', 
      details: error.response ? error.response.data : error.message 
    });
  }
});

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

